### What is Middleware?

Middleware runs code **before a request completes**. It executes at the edge, allowing you to modify the request/response before pages or API routes handle them.

### Creating Middleware

Create `middleware.ts` (or `.js`) at the root of your project (same level as `app/` or `pages/`):

```ts
// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  console.log('Middleware running for:', request.url);
  return NextResponse.next();
}
```

### Matcher Config

Control which paths trigger middleware:

```ts
export const config = {
  matcher: [
    '/dashboard/:path*',
    '/api/:path*',
    '/((?!api|_next/static|_next/image|favicon.ico).*)',
  ],
};
```

### Request Rewriting

Rewrite URLs without changing the browser address:

```ts
import { NextResponse } from 'next/server';

export function middleware(request: NextRequest) {
  if (request.nextUrl.pathname === '/old-path') {
    return NextResponse.rewrite(new URL('/new-path', request.url));
  }
}
```

### Redirects

Redirect users:

```ts
export function middleware(request: NextRequest) {
  const country = request.geo?.country || 'US';

  if (country === 'DE') {
    return NextResponse.redirect(new URL('/de', request.url));
  }
}
```

### Headers Modification

Add or modify response headers:

```ts
export function middleware(request: NextRequest) {
  const requestHeaders = new Headers(request.headers);
  requestHeaders.set('x-custom-header', 'hello');

  const response = NextResponse.next({
    request: { headers: requestHeaders },
  });

  response.headers.set('x-response-custom', 'from-middleware');
  return response;
}
```

### Authentication Checks

```ts
import { NextResponse } from 'next/server';

export function middleware(request: NextRequest) {
  const token = request.cookies.get('auth-token')?.value;
  const isAuthPage = request.nextUrl.pathname.startsWith('/login');

  if (!token && !isAuthPage) {
    return NextResponse.redirect(new URL('/login', request.url));
  }

  if (token && isAuthPage) {
    return NextResponse.redirect(new URL('/dashboard', request.url));
  }

  return NextResponse.next();
}

export const config = {
  matcher: ['/dashboard/:path*', '/profile/:path*', '/login'],
};
```

codeExample:
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;
  const isAuthenticated = request.cookies.has('session');

  const protectedPaths = ['/dashboard', '/profile', '/settings'];
  const isProtected = protectedPaths.some(p => pathname.startsWith(p));

  if (isProtected && !isAuthenticated) {
    const loginUrl = new URL('/login', request.url);
    loginUrl.searchParams.set('redirect', pathname);
    return NextResponse.redirect(loginUrl);
  }

  return NextResponse.next();
}

export const config = {
  matcher: ['/dashboard/:path*', '/profile/:path*', '/settings/:path*', '/login'],
};
